  4066→int sata_link_hardreset(struct ata_link *link, const unsigned long *timing,
  4067→			unsigned long deadline,
  4068→			bool *online, int (*check_ready)(struct ata_link *))
  4069→{
  4070→	u32 scontrol;
  4071→	int rc;
  4072→
  4073→	DPRINTK("ENTER
");
  4074→
  4075→	if (online)
